<template>

    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tglistuser" :IsShowAction="true" :showCheckBox="true" :listType="['List']" ModuleName="Company"
            SubModuleCode="CMP_USER" IdentityColumn="user_id" HeaderText="Manage Device" :ListData="devices"
            :HeaderData="Headers" :ViewList="ViewList" v-on:ApplyView="OnApplyView"
            v-on:RefreshManageView="FetchUserData" :callbackfunction="FetchUserData" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions"
            :IsFilterApplied="searchCondition ? true : false" :ListDataCallBackFunction="FetchUserData"
            :LegendArray="LegendArray" :SortExp="sortExp" :SortBy="sortBy" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata" :widgets="widgets">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME === 'online'">
                    <div class="status-indicator" :class="data.row.online ? 'status-active' : 'status-inactive'"></div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'statusId'">
                    <listing-status :isfor="'USER'" ref="updatestatus" v-bind:dataid="data.row.statusId" Missing
                        required prop: module="Company" subModule="CannedReply" data-controller="compnay"
                        v-bind:statuslist="StatusListForListing" v-bind:item="data.statusId" data-action="index"
                        v-bind:dataselected="data.row.statusId == null ? 'New device register' : data.row.statusId == 1001 ? 'Active' : 'Inactive'"
                        v-bind:isselectedvaluestring="true"
                        v-bind:title="data.row.statusId == 1001 ? 'Active' : 'Inactive'"
                        @change="FetchRecords(data.row)">
                    </listing-status>
                </template>
            </template>
        </tg-list>
        <DeviceDetailView v-if="deviceDetailShow" @close="deviceDetailShow = false" :deviceRecord="deviceRecord"
            @submitRecord="changeEditRecord($event)" />
    </section>
</template>

<script>
import DataService from "../../services/DataService";
import DeviceDetailView from "./DeviceDetailView.vue";
import Schema from "./DeviceListingSchema";
import { data } from 'jquery';
export default {
    components: {
        DeviceDetailView,
    },
    data() {
        return {
            isLoading: false,
            deviceDetailShow: false,
            noRecord: false,
            leftSearchFields: Schema.leftsearchSchema,
            listheaderbuttons: Schema.buttons,
            listActions: Schema.listActions,
            ViewList: [],
            ViewListId: "",
            searchCondition: "",
            PageSize: 4,
            PageNumber: 1,
            GetUserListing: [],
            GetExcelListing: [],
            exportExcelSchema: [],
            Headers: [],
            TotalRecords: 0,
            TotalPages: 20,
            widgets: [
                {
                    icon: "fas fa-tablet-alt",
                    value: 0,
                    name: "Total Devices",
                    class: "one_wid",
                    onClick: this.widgetClick,
                },
                {
                    icon: "fas fa-check-circle",
                    value: 0,
                    name: "Active Devices",
                    class: "two_wid",
                    onClick: this.widgetClick,
                },
                {
                    icon: "fas fa-times-circle",
                    value: 0,
                    name: "Inactive Devices",
                    class: "three_wid",
                    onClick: this.widgetClick,
                },
                {
                    icon: "fas fa-sync-alt",
                    value: 0,
                    name: "Avg. Sync Interval",
                    class: "four_wid",
                    onClick: this.widgetClick,
                },
            ],
            LegendArray: [],
            userid: null,
            usertype: "",
            companyId: null,
            sortExp: "ASC",
            sortBy: "CREATED_AT",
            devices: [],
            lastOnlinePing: Date.now(),
            offlineTimer: null,
            StatusListForListing: [
                //{ STATUS: 'New device register', STATUS_ID: null, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#28a745" },
                { STATUS: 'Active', STATUS_ID: 1001, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#28a745" },
                { STATUS: 'Inactive', STATUS_ID: 1002, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#d72435" }],
            deviceRecord: {}
        };
    },
    sockets: {
        connect() {
            console.log("🟢 Socket connected:", this.$socket.id);
        },
        disconnect() {
            console.log("🔴 Socket disconnected");
        },
        connect_error(err) {
            console.error("❌ Socket connection error:", err);
        },
        showOnlineDeviceWeb(data) {
    const now = Date.now();

    this.devices = this.devices.map(device => {
        if (device.uniqueCode === data.deviceId) {
            return {
                ...device,
                online: true,
                lastPing: now
            };
        }
        return device; // keep other devices unchanged
    });
},
    },
    async created() {
        this.Headers = [
            {
                COLUMN_NAME: "online",
                DATA_TYPE: "text",
                SORTABLE: false,
                VISIBLE: true,
                DISPLAY_NAME: "Online",
                DISPLAY_ORDER: 1,
                settings: { isInSlot: true },
            },
            {
                COLUMN_NAME: "deviceName",
                DATA_TYPE: "text",
                SORTABLE: true,
                VISIBLE: true,
                DISPLAY_NAME: "Device Name",
                DISPLAY_ORDER: 2,
            },
            {
                COLUMN_NAME: "ipAddress",
                DATA_TYPE: "text",
                SORTABLE: true,
                VISIBLE: true,
                DISPLAY_NAME: "IP Address",
                DISPLAY_ORDER: 3,
            },
            {
                COLUMN_NAME: "uniqueCode",
                DATA_TYPE: "text",
                SORTABLE: true,
                VISIBLE: true,
                DISPLAY_NAME: "Device ID",
                DISPLAY_ORDER: 8,
            },
            {
                COLUMN_NAME: "serialNumber",
                DATA_TYPE: "text",
                SORTABLE: true,
                VISIBLE: true,
                DISPLAY_NAME: "Serial Number",
                DISPLAY_ORDER: 7,
            },

            {
                COLUMN_NAME: "subLocation",
                DATA_TYPE: "text",
                SORTABLE: true,
                VISIBLE: true,
                DISPLAY_NAME: "Location",
                DISPLAY_ORDER: 9,
            },
            {
                COLUMN_NAME: "apiUrl",
                DATA_TYPE: "text",
                SORTABLE: true,
                VISIBLE: true,
                DISPLAY_NAME: "Face Auth URL",
                DISPLAY_ORDER: 4,
            },
            {
                COLUMN_NAME: "lastSync",
                DATA_TYPE: "text",
                SORTABLE: true,
                VISIBLE: true,
                DISPLAY_NAME: "Last Sync",
                DISPLAY_ORDER: 5,
            },
            {
                COLUMN_NAME: "statusId",
                DATA_TYPE: "text",
                SORTABLE: false,
                VISIBLE: true,
                DISPLAY_NAME: "Status",
                DISPLAY_ORDER: 6,
                settings: { isInSlot: true },
            },
        ];
        this.devices = [];
    },
    computed: {
        deviceList() {
            return this.devices.filter((d) => d.statusId === 1001);
        },
        totalDevices() {
            return this.devices.length;
        },

        activeDevices() {
            return this.devices.filter((d) => d.statusId === 1001).length;
        },

        inactiveDevices() {
            return this.devices.filter((d) => d.statusId === 1002).length;
        },

        avgSyncInterval() {
            if (!this.devices.length) return 0;

            const total = this.devices.reduce((sum, d) => sum + (d.syncFrequency || 0), 0);

            return Math.round(total / this.devices.length) + 'M';
        },
    },
    mounted() {
        this.offlineDevice();
        this.FetchUserData();
    },
    watch: {
        devices: {
            deep: true,
            immediate: true,
            handler() {
                this.widgets = this.widgets.map((widget) => {
                    switch (widget.name) {
                        case "Total Devices":
                            return { ...widget, value: this.totalDevices };

                        case "Active Devices":
                            return { ...widget, value: this.activeDevices };

                        case "Inactive Devices":
                            return { ...widget, value: this.inactiveDevices };

                        case "Avg. Sync Interval":
                            return { ...widget, value: this.avgSyncInterval };

                        default:
                            return widget;
                    }
                });
            },
        },
    },
    beforeDestroy() {
        clearInterval(this.offlineTimer);
    },

    methods: {
        async FetchUserData() {
            this.isLoading = true;
            //long CompanyId, string uniqueCode, int pageNumber = 1, int pageSize = 20, string sortColumn = "device_id", string sortDirection = "ASC"
            const result = await DataService.DeviceList(
                `companyId=${this.GetUserInfo.CompanyId}&pageNumber=${this.PageNumber}&pageSize=${this.PageSize}&sortColumn=${this.sortBy}&sortDirection=${this.sortExp}`
            );

            const devices = result.data || [];
            this.devices = devices.map(device => {

                return {
                    ...device,
                    online: false,

                };
            });
            this.TotalRecords = devices.length;
            // Save devices list
            this.isLoading = false;
            // this.devices = devices;
        },
        async FetchRecords(device) {
            this.isLoading = true;
            console.log("Status change for device:", device);
            const vm = this;
            // 🔥 1. Update UI immediately
            const index = vm.devices.findIndex(
                d => d.deviceId === device.deviceId
            );

            if (index !== -1) {
                const newStatus = vm.devices[index].statusId === 1001 ? 1002 : 1001;

                // Vue-safe update
                vm.$set(vm.devices, index, {
                    ...vm.devices[index],
                    statusId: newStatus,
                });


                await DataService.DeviceRegister(vm.devices[index]);
                // 🔥 2. Emit socket AFTER local update
                vm.$socket.emit("activeStatus", {
                    deviceId: device.uniqueCode,
                    statusId: newStatus,
                    apiUrl: device.apiUrl
                });
            }
            this.isLoading = false;
        },
        pagerMethod: async function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            await this.FetchUserData();
        },
        changeEditRecord(record) {
            //console.log("updated record in parent", record);
            const index = this.devices.findIndex(
                d => d.deviceId === record.deviceId
            );
            if (index !== -1) {
                this.$set(this.devices, index, {
                    ...this.devices[index],
                    ...record
                })
            }
            this.deviceDetailShow = false;
        },

        offlineDevice() {
            this.offlineTimer = setInterval(() => {
                const now = Date.now();
                this.devices = this.devices.map(device => {
                    if (!device.lastPing) return device;
                    const diff = now - device.lastPing;
                    if (diff > 15000) {
                        return {
                            ...device,
                            online: false
                        };
                    }

                    return device;
                });
            }, 5000);
        },
        showOnlineDevice(data) {
            const now = Date.now();

            this.devices = this.devices.map(device => {
                if (device.deviceId === data.deviceId) {
                    return {
                        ...device,
                        online: true,
                        lastPing: now
                    };
                }
                return device;
            });
        },
        commonHeaderButtonClick(event) {
            switch (event.callbackfunction) {
                case "removeFilter":
                    //ths.FetchUserData();
                    break;
            }
        },

        leftCommonSearch: async function (value) {
            this.PageNumber = value.PageNumber;
            //this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                this.searchCondition = value.searchCondition;
            }
            else {
                this.searchCondition = "";
            }
            await this.FetchUserData();
        },
        OnApplyView: function () {

        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.sortBy = s;
            if (s === this.sortBy) {
                if (this.sortExp == "") {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                } else if (this.sortExp == "ASC") {
                    this.sortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                } else {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            //this.FetchUserData();
            //$("#" + s + "  span:first-child").attr("class", SortDir);
        },
        actionButtonClick: function (callbackfunction, item, index, event) {
            console.log("checkk", callbackfunction, item, index, event);
            var vm = this;
            switch (callbackfunction) {
                case "ViewUserDetails":
                    vm.deviceRecord = item;
                    this.deviceDetailShow = true;
                    break;
                case "sync":
                    this.AssignManager();
                    break;
                case "remoteLog":
                    //this.ManageView();
                    break;
                case "DefaultProject":
                    // vm.DefaultProduct(item);
                    break;
            }
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach((actionItem) => {
                let action = { ...actionItem };
                switch (action.title) {
                    case "View":
                        action.isVisible = true;
                        break;

                    default:
                        action.isVisible = true;
                        break;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
    },
};
// Sample device data

// Sample sync logs for each device
</script>

<style>
.status-active {
    background-color: #10b981;
    box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.2);
}

.status-inactive {
    background-color: #ef4444;
    box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.2);
}

.status-indicator {
    width: 10px;
    height: 10px;
    border-radius: 50%;
}
</style>
